1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 110;
3	
4	type Item = { type: string; cursed?: boolean; enchantment?: number };
5	type Scenario = { steps: { items: Item[] }[] };
6	
7	type ItemKind = {
8	  basePremium: number;
9	  isComponent: boolean;
10	};
11	
12	const ITEM_CATALOG: Record<string, ItemKind> = {
13	  sword: { basePremium: 100, isComponent: false },
14	  amulet: { basePremium: 60, isComponent: false },
15	  staff: { basePremium: 80, isComponent: false },
16	  potion: { basePremium: 40, isComponent: false },
17	  rune: { basePremium: 25, isComponent: true },
18	  moonstone: { basePremium: 25, isComponent: true },
19	};
20	
21	const BLOCK_PRICE = 60;
22	const BLOCK_SIZE = 3;
23	
24	const countByType = (items: Item[]): Record<string, number> =>
25	  items.reduce<Record<string, number>>((counts, item) => {
26	    counts[item.type] = (counts[item.type] ?? 0) + 1;
27	    return counts;
28	  }, {});
29	
30	const premiumForTypeGroup = (type: string, count: number): number => {
31	  const kind = ITEM_CATALOG[type];
32	  const formsBlock = kind.isComponent && count === BLOCK_SIZE;
33	  return formsBlock ? BLOCK_PRICE : kind.basePremium * count;
34	};
35	
36	const policyBaseFor = (items: Item[]): number =>
37	  Object.entries(countByType(items)).reduce(
38	    (total, [type, count]) => total + premiumForTypeGroup(type, count),
39	    0,
40	  );
41	
42	const CURSE_SURCHARGE_RATE = 0.5;
43	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
44	const HIGH_ENCHANTMENT_THRESHOLD = 5;
45	
46	const itemSurchargeFor = (item: Item): number => {
47	  const basePremium = ITEM_CATALOG[item.type].basePremium;
48	  const curseSurcharge = item.cursed ? basePremium * CURSE_SURCHARGE_RATE : 0;
49	  const highEnchantmentSurcharge =
50	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
51	      ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
52	      : 0;
53	  return curseSurcharge + highEnchantmentSurcharge;
54	};
55	
56	const perItemSurchargesFor = (items: Item[]): number =>
57	  items.reduce((total, item) => total + itemSurchargeFor(item), 0);
58	
59	const applyPolicyModifiers = (policyBase: number): number =>
60	  Math.ceil((policyBase * FIRST_INSURANCE_PERCENT) / 100);
61	
62	const quoteFor = (items: Item[]): number =>
63	  applyPolicyModifiers(policyBaseFor(items)) +
64	  perItemSurchargesFor(items) +
65	  PROCESSING_FEE;
66	
67	export const runScenario = (input: unknown): unknown => {
68	  const items = (input as Scenario).steps[0].items;
69	  return { results: [{ premium: quoteFor(items) }] };
70	};
