const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const ITEM_SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
];

const itemSurchargeFor = (item: Item): number => {
  const basePremium = ITEM_CATALOG[item.type].basePremium;
  return ITEM_SURCHARGE_RULES.reduce(
    (total, rule) => total + (rule.applies(item) ? basePremium * rule.rate : 0),
    0,
  );
};

